#include <bits/stdc++.h>using namespace std;typedef long long ll;ll dynamic(int i,int j,int p, vector<ll> &l, vector<ll> &r,vector<vector<ll>> &adj, vector<vector<ll>> &dp){    if(dp[i][j]!=-1) return dp[i][j];    ll ans = 0;    for(int m=0; m<adj[i].size(); m++){        int k = adj[i][m];        if(k != p){            ll left = dynamic(k,0,i,l,r,adj,dp);            ll right = dynamic(k,1,i,l,r,adj,dp);            if(j==0){                ans += max(left + abs(l[i]-l[k]),right + abs(l[i]-r[k]));            }            else{                ans += max(left + abs(r[i]-l[k]),right + abs(r[i]-r[k]));            }        }    }    return dp[i][j] = ans;}int main() {    ios::sync_with_stdio(false);    cin.tie(NULL);    ll t;    cin >> t;    while(t--){        ll n;        cin >> n;        vector<ll> l(n);        vector<ll> r(n);        vector<vector<ll>> adj(n);        for(int i=0;i<n;i++){            cin>> l[i] >> r[i];        }        for(int i=0;i<n-1;i++){            ll u,v;            cin >> u >> v;            u--;v--;            adj[u].push_back(v);            adj[v].push_back(u);        }        vector<vector<ll>> dp(n,vector<ll>(2,-1));        cout << max(dynamic(0,0,-1,l,r,adj,dp), dynamic(0,1,-1,l,r,adj,dp)) << endl;    }}